import { useState, useRef } from "react";
import EmotionBar from "./components/EmotionBar";
import VADGraph from "./components/VADGraph";
import "./App.css";

const API = "http://localhost:8000";

export default function App() {
  const [text, setText] = useState("");
  const [result, setResult] = useState(null);
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const textRef = useRef();

  async function analyze() {
    if (!text.trim()) return;
    setLoading(true);
    setError("");
    try {
      const res = await fetch(`${API}/analyze`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text }),
      });
      if (!res.ok) throw new Error(await res.text());
      const data = await res.json();
      setResult(data);
      setHistory((h) => [...h, { text: text.slice(0, 40), ...data }]);
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  }

  const bgStyle = result
    ? {
        backgroundColor: `hsl(${result.color.h}, ${result.color.s}%, ${result.color.l}%)`,
        transition: "background-color 1.5s ease",
      }
    : {};

  return (
    <div className="app" style={bgStyle}>
      <h1>ColorfulSpeech</h1>
      <p className="subtitle">Language → Emotional Geometry → Color</p>

      <div className="input-row">
        <textarea
          ref={textRef}
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="Enter text to analyze…"
          rows={4}
          onKeyDown={(e) => e.key === "Enter" && e.ctrlKey && analyze()}
        />
        <button onClick={analyze} disabled={loading}>
          {loading ? "Analyzing…" : "Analyze"}
        </button>
      </div>

      {error && <p className="error">{error}</p>}

      {result && (
        <div className="results">
          <div className="card explanation">
            <p>{result.explanation}</p>
            <div className="vad-nums">
              <span>V <strong>{result.vad.valence > 0 ? "+" : ""}{result.vad.valence.toFixed(2)}</strong></span>
              <span>A <strong>{result.vad.arousal.toFixed(2)}</strong></span>
              <span>D <strong>{result.vad.dominance.toFixed(2)}</strong></span>
            </div>
          </div>

          <div className="charts">
            <div className="card">
              <h3>Emotion Distribution</h3>
              <EmotionBar emotions={result.emotions} />
            </div>
            <div className="card">
              <h3>VAD Space</h3>
              <VADGraph history={history} current={result.vad} />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { Scatter } from "react-chartjs-2";
import {
  Chart as ChartJS,
  LinearScale,
  PointElement,
  Tooltip,
  LineElement,
} from "chart.js";

ChartJS.register(LinearScale, PointElement, Tooltip, LineElement);

export default function VADGraph({ history, current }) {
  // history points (faded), current point (bright)
  const histPoints = history.slice(0, -1).map((h) => ({
    x: h.vad.valence,
    y: h.vad.arousal,
    r: h.vad.dominance * 12 + 4,
  }));
  const curPoint = { x: current.valence, y: current.arousal };

  const data = {
    datasets: [
      {
        label: "History",
        data: histPoints,
        backgroundColor: "rgba(150,150,255,0.35)",
        pointRadius: histPoints.map((p) => p.r),
      },
      {
        label: "Current",
        data: [curPoint],
        backgroundColor: "rgba(255,220,50,0.9)",
        pointRadius: current.dominance * 14 + 6,
        pointHoverRadius: 14,
      },
    ],
  };

  const options = {
    plugins: { legend: { display: false } },
    scales: {
      x: {
        min: -1, max: 1,
        title: { display: true, text: "Valence", color: "#aaa" },
        ticks: { color: "#ccc" },
        grid: { color: "#333" },
      },
      y: {
        min: 0, max: 1,
        title: { display: true, text: "Arousal", color: "#aaa" },
        ticks: { color: "#ccc" },
        grid: { color: "#333" },
      },
    },
    responsive: true,
    maintainAspectRatio: false,
  };

  return <div style={{ height: 260 }}><Scatter data={data} options={options} /></div>;
}

import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip);

const COLORS = {
  joy: "#f5c518",
  love: "#e91e8c",
  gratitude: "#ff9800",
  amusement: "#ffd54f",
  excitement: "#ff6d00",
  neutral: "#90a4ae",
  surprise: "#00bcd4",
  anger: "#f44336",
  fear: "#7b1fa2",
  disgust: "#558b2f",
  sadness: "#1565c0",
  disappointment: "#5c6bc0",
  grief: "#283593",
  embarrassment: "#ad1457",
  confusion: "#0097a7",
};

export default function EmotionBar({ emotions }) {
  const sorted = Object.entries(emotions).sort((a, b) => b[1] - a[1]);
  const data = {
    labels: sorted.map(([e]) => e),
    datasets: [{
      data: sorted.map(([, v]) => v),
      backgroundColor: sorted.map(([e]) => COLORS[e] ?? "#888"),
      borderRadius: 4,
    }],
  };
  const options = {
    indexAxis: "y",
    plugins: { legend: { display: false } },
    scales: {
      x: { min: 0, max: 1, ticks: { color: "#ccc" }, grid: { color: "#333" } },
      y: { ticks: { color: "#ccc" }, grid: { display: false } },
    },
    responsive: true,
    maintainAspectRatio: false,
  };
  return <div style={{ height: 260 }}><Bar data={data} options={options} /></div>;
}

